
"use client";
import { useState, useEffect } from "react";
import Image from 'next/image';
import Link from 'next/link';
import {
  Home,
  FileText,
  CalendarCheck,
  FlaskConical,
  History,
  Settings,
  LogOut,
  Users,
  Filter,
  RefreshCw
} from 'lucide-react';
import { usePathname } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { addAuditLogAction, getLabRequestsAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { LabRequest } from "@/utils/storage";

const AdminSidebar = () => {
    const { user, logout } = useAuth();
    const pathname = usePathname();

    const handleLogout = async () => {
        if(user) {
            await addAuditLogAction({ userId: user.id, userName: user.name, action: 'logout' });
        }
        logout();
    };

    const sidebarNavItems = [
        { title: 'Dashboard', icon: Home, href: '/dashboard' },
        { title: 'Manage Users', icon: Users, href: '/admin/users' },
        { title: 'All Requests', icon: FileText, href: '/admin/requests' },
        { title: 'Attendance Reports', icon: CalendarCheck, href: '/admin/reports' },
        { title: 'Lab Management', icon: FlaskConical, href: '/admin/labs' },
        { title: 'Audit Log', icon: History, href: '/admin/audit' },
        { title: 'System Settings', icon: Settings, href: '/admin/settings' },
    ];

    return (
        <aside className="w-64 bg-white p-5 flex flex-col border-r shrink-0">
            <div className="text-center mb-6 mt-2">
                <Link href="/profile">
                    <div className="w-16 h-16 rounded-md bg-primary text-white flex items-center justify-center mx-auto mb-3 cursor-pointer">
                        <span className="text-2xl font-bold">{user?.name?.charAt(0) || 'A'}</span>
                    </div>
                </Link>
                <h3 className="font-semibold text-gray-800">Administrator</h3>
                <p className="text-sm text-muted-foreground">{user?.name}</p>
            </div>
            
            <Button variant="ghost" className="justify-start gap-3 text-base font-medium text-gray-600 hover:text-primary mb-4">
                <RefreshCw className="w-5 h-5" /> Refresh
            </Button>

            <nav className="flex-grow space-y-2">
                {sidebarNavItems.map((item) => {
                    const isActive = pathname === item.href;
                    return (
                        <Link key={item.title} href={item.href} passHref>
                            <Button
                                variant={isActive ? 'default' : 'ghost'}
                                className={`w-full justify-start gap-3 text-base font-medium ${isActive ? 'text-white' : 'text-gray-600 hover:text-primary hover:bg-primary/5'}`}
                                style={isActive ? { backgroundColor: '#E30613' } : {}}
                            >
                                <item.icon className={`w-5 h-5 ${isActive ? 'text-white' : 'text-gray-400 group-hover:text-primary'}`} />
                                {item.title}
                            </Button>
                        </Link>
                    )
                })}
            </nav>
            
            <div className="mt-auto">
                <Button onClick={handleLogout} variant="ghost" className="w-full justify-start gap-3 text-base font-medium text-red-500 hover:text-red-700 hover:bg-red-50">
                    <LogOut className="w-5 h-5" />
                    Logout
                </Button>
            </div>
        </aside>
    );
}

export default function RequestManagementPage() {
    const [requests, setRequests] = useState<LabRequest[]>([]);
    const [filter, setFilter] = useState('all');

    useEffect(() => {
        const fetchRequests = async () => {
            setRequests(await getLabRequestsAction());
        };
        fetchRequests();
    }, []);

    const filteredRequests = requests.filter(r => filter === 'all' || r.status === filter);

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <header className="bg-primary shadow-lg sticky top-0 z-20">
                <div className="mx-auto px-8 h-16 flex items-center">
                    <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
                </div>
            </header>
            <div className="flex flex-1">
                <AdminSidebar />
                <main className="flex-1 p-8 overflow-y-auto">
                    <div className="mb-8">
                        <h1 className="text-3xl font-bold text-gray-800">Request Management</h1>
                        <p className="text-muted-foreground">Track all student requests for LAB/room bookings.</p>
                    </div>

                    <div className="flex items-center gap-2 mb-6">
                        <Filter className="h-5 w-5 text-gray-500" />
                        <Button variant={filter === 'all' ? 'default' : 'outline'} onClick={() => setFilter('all')} style={filter === 'all' ? { backgroundColor: '#E30613' } : {}}>All</Button>
                        <Button variant={filter === 'pending' ? 'default' : 'outline'} onClick={() => setFilter('pending')} style={filter === 'pending' ? { backgroundColor: '#E30613' } : {}}>Pending</Button>
                        <Button variant={filter === 'approved' ? 'default' : 'outline'} onClick={() => setFilter('approved')} style={filter === 'approved' ? { backgroundColor: '#E30613' } : {}}>Approved</Button>
                        <Button variant={filter === 'declined' ? 'default' : 'outline'} onClick={() => setFilter('declined')} style={filter === 'declined' ? { backgroundColor: '#E30613' } : {}}>Declined</Button>
                    </div>

                    <Card>
                        <CardContent className="pt-6">
                            {filteredRequests.length === 0 ? (
                                <p className="text-center text-muted-foreground py-10">No requests found for this filter.</p>
                            ) : (
                                <div className="space-y-4">
                                    {/* Placeholder for request items */}
                                    <p className="text-center text-muted-foreground py-10">Request list will be implemented here.</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                </main>
            </div>
        </div>
    );
}
